/** Minimal fixed header: wordmark + demo CTA over a soft white fade. */
export default function Header() {
  return (
    <header className="fixed inset-x-0 top-0 z-30">
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-b from-white/90 via-white/45 to-transparent" />
      <div className="relative mx-auto flex h-16 max-w-6xl items-center justify-between px-5 md:px-10">
        <a href="#top" className="flex items-center gap-2.5 text-[17px] font-semibold tracking-tight text-ink">
          <LogoMark />
          {SITE.name}
        </a>
        <a
          href={SITE.demoHref}
          className="hidden items-center rounded-full px-4 py-2 text-[13px] font-semibold text-white shadow-button transition hover:brightness-110 sm:inline-flex"
          style={{ backgroundImage: 'linear-gradient(100deg, #0D9488, #7C3AED)' }}
        >
          Book a demo
        </a>
      </div>
    </header>
  )
}
